// Avatar placeholder with initials
const Avatar: React.FC<{ name: string; bg: string }> = ({ name, bg }) => {
  const initials = name
    .split(" ")
    .map((n) => n[0])
    .slice(0, 2)
    .join("");
  return (
    <div
      className="sidebar-avatar"
      style={{
        background: bg,
        width: 32,
        height: 32,
        fontSize: 12,
        flexShrink: 0,
      }}
    >
      {initials}
    </div>
  );
};

